const headers = $input.item.json.headers || {};
const body    = $input.item.json.body    || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const message = (body.message || '').toString().trim();
if (!message) return { json: { ok: false, status: 400, error: 'Missing message' } };
if (message.length > 4000) return { json: { ok: false, status: 400, error: 'Message too long (max 4000 chars)' } };
return { json: { token, message } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
return { json: { ok: true, user_id: row.user_id || row.id, user_email: row.user_email || row.email } };

const raw = $input.item.json;
let sessionId = null;
if (typeof raw === 'string') sessionId = raw.replace(/"/g, '');
else if (Array.isArray(raw) && raw.length) sessionId = raw[0];
else if (raw && raw.find_or_create_active_chat_session) sessionId = raw.find_or_create_active_chat_session;
if (!sessionId) return { json: { ok: false, status: 500, error: 'Could not resolve chat session' } };
return { json: { session_id: sessionId } };

// Build the Anthropic request body from persisted history (which already
// includes the just-saved user message).
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};
const history = allOf('Load History');

const systemPrompt = [
  'You are the Crystallux Assistant — an in-app helper for Mary (the platform founder) and any admin user logged into the Crystallux dashboard.',
  '',
  'Be helpful, concise, and direct. Match the tone of a senior teammate: warm but no fluff, no marketing language, no apologies. Use plain words, not jargon. When relevant, suggest concrete next actions Mary can take in the dashboard or on her VPS.',
  '',
  'About the platform Mary built:',
  '- Crystallux is a sales operating system: lead discovery (city scan), AI-driven outreach (email/SMS/WhatsApp/voice via Vapi), booking automation, post-call analysis, behavioral intelligence, and per-channel reporting.',
  '- It is multi-vertical: Smart Quote handles 7 industries (insurance_personal, construction, dental, cleaning, restaurants, moving, beauty) plus MAXI templates for 21 SMB industries.',
  '- Avatars: LUXI (live commerce auctions), AVA (insurance education broadcasts), MAXI (SMB growth), CIRO (operations + alerts + comms log), MGA (insurance Managing General Agency).',
  '- Sentinel monitors cost, health, security, comms delivery, and can auto-pause workflows on threshold breaches.',
  '- Frontend: Cloudflare Pages. Backend: n8n + Supabase Postgres + Postmark + Twilio + Vapi + Stripe.',
  '',
  'Key admin pages: overview, sales-engine, sentinel (Overview/Costs/Health/Security/Communications/Remediation/Alerts), ciro/communications, ciro/alerts, smart-quote, avatars/luxi, avatars/ava, carriers, system/dev-console.',
  '',
  'Rules:',
  '- For platform status questions, point to the relevant dashboard page and what they should see.',
  '- If asked to TAKE an action (send email, create booking, etc.), explain that action execution is coming in the next chat-widget version. Today you only answer questions and suggest commands.',
  '- For API signups, refer to docs/PLATFORM_BACKLOG.md item 9.',
  '- Never invent stats. If unknown, say so and suggest where to look.',
  '- Keep answers under 200 words unless asked for detail.',
  '- No em-dashes. Use periods, commas, line breaks instead.',
  '- This conversation is persisted, so referencing earlier exchanges is fine.'
].join('\n');

const messages = history.filter(function (m) {
  return m && m.content && (m.role === 'user' || m.role === 'assistant');
}).map(function (m) {
  return { role: m.role, content: String(m.content).slice(0, 4000) };
});

return { json: {
  payload: {
    model: 'claude-sonnet-4-6',
    max_tokens: 1024,
    system: systemPrompt,
    messages: messages
  }
} };

const r = $input.item.json;
if (!r || r.type === 'error' || r.error) {
  const err = (r && (r.error && r.error.message)) || 'Claude call failed';
  return { json: { ok: false, status: 502, error: err } };
}
const textBlock = (r.content || []).find(function (c) { return c && c.type === 'text'; });
const text = textBlock ? textBlock.text : '';
if (!text) return { json: { ok: false, status: 502, error: 'Empty response from Claude' } };
return { json: { response: text, model: r.model || null, stop_reason: r.stop_reason || null, usage: r.usage || null } };

const parsed = $('Parse Claude').first().json;
const sess   = $('Normalize Session').first().json;
return { json: { ok: true, data: {
  response: parsed.response,
  session_id: sess.session_id,
  model: parsed.model,
  stop_reason: parsed.stop_reason,
  usage: parsed.usage
} } };
